	handlers.ForEach(ipch.RegisterService)
	handlers.ForEach(grpcServer.RegisterService)

	// register grpcServer graceful stop on shutdown
	server.onShutdown(func(context.Context) error {
		healthsrv.Shutdown()
		grpcServer.GracefulStop()
